arguments.new_str:
using Microsoft.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 42);

var csvPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    csvPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" label to boolean, encode Region, and combine features
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
        (input, output) => output.Label = input.Churned == "Yes",
        contractName: "ChurnLabelMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

Console.WriteLine("Training churn model...");
var model = pipeline.Fit(dataView);
Console.WriteLine("Model trained.");

var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel ? "Yes" : "No",
        Confidence = Math.Round(prediction.Probability * 100, 1)
    });
});

app.Run();

public sealed class LabelMapping
{
    public bool Label { get; set; }
}

public sealed record PredictRequest(float Age, float Income, string Region, float PurchaseHistory);

